const upsertExternalIdentity = `-- name: UpsertExternalIdentity :one

INSERT INTO external_identity (
    workspace_id, provider, external_account_id, external_login,
    display_name, email, avatar_url, user_id
) VALUES (
    $1, $2, $3, $4,
    $5, $6, $7,
    $8
)
ON CONFLICT (workspace_id, provider, external_account_id) DO UPDATE SET
    external_login = COALESCE(EXCLUDED.external_login, external_identity.external_login),
    display_name   = COALESCE(EXCLUDED.display_name, external_identity.display_name),
    email          = COALESCE(EXCLUDED.email, external_identity.email),
    avatar_url     = COALESCE(EXCLUDED.avatar_url, external_identity.avatar_url),
    user_id        = COALESCE(external_identity.user_id, EXCLUDED.user_id),
    updated_at     = now()
RETURNING id, workspace_id, provider, external_account_id, external_login, display_name, email, avatar_url, user_id, created_at, updated_at
`

type UpsertExternalIdentityParams struct {
	WorkspaceID       pgtype.UUID `json:"workspace_id"`
	Provider          string      `json:"provider"`
	ExternalAccountID string      `json:"external_account_id"`
	ExternalLogin     pgtype.Text `json:"external_login"`
	DisplayName       pgtype.Text `json:"display_name"`
	Email             pgtype.Text `json:"email"`
	AvatarUrl         pgtype.Text `json:"avatar_url"`
	UserID            pgtype.UUID `json:"user_id"`
}

// =====================
// External Identities
// =====================
func (q *Queries) UpsertExternalIdentity(ctx context.Context, arg UpsertExternalIdentityParams) (ExternalIdentity, error) {
	row := q.db.QueryRow(ctx, upsertExternalIdentity,
		arg.WorkspaceID,
		arg.Provider,
		arg.ExternalAccountID,
		arg.ExternalLogin,
		arg.DisplayName,
		arg.Email,
		arg.AvatarUrl,
		arg.UserID,
	)
	var i ExternalIdentity
	err := row.Scan(
		&i.ID,
		&i.WorkspaceID,
		&i.Provider,
		&i.ExternalAccountID,
		&i.ExternalLogin,
		&i.DisplayName,
		&i.Email,
		&i.AvatarUrl,
		&i.UserID,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
